from __future__ import annotations

from dataclasses import dataclass, replace
from decimal import Decimal
from enum import Enum


class ShoppingCartError(Exception):
    """Base exception for shopping cart errors."""


class InvalidProductNameError(ShoppingCartError):
    """Raised when a product name is empty or invalid."""


class InvalidUnitPriceError(ShoppingCartError):
    """Raised when a unit price is negative."""


class InvalidQuantityError(ShoppingCartError):
    """Raised when a quantity is less than one."""


class ItemNotFoundError(ShoppingCartError):
    """Raised when an item does not exist in the cart."""


class DuplicateItemPriceMismatchError(ShoppingCartError):
    """Raised when adding an existing product with a different unit price."""


class InvalidDiscountError(ShoppingCartError):
    """Raised when a discount value is invalid."""


class DiscountType(Enum):
    """Supported discount calculation types."""

    PERCENTAGE = "percentage"
    FLAT = "flat"


@dataclass(frozen=True, slots=True)
class CartItem:
    """Represents one product entry in a shopping cart."""

    product_name: str
    unit_price: Decimal
    quantity: int

    @property
    def line_total(self) -> Decimal:
        """Return the total price for this item before discounts."""
        return self.unit_price * self.quantity


@dataclass(frozen=True, slots=True)
class Discount:
    """Represents a discount applied to a shopping cart."""

    discount_type: DiscountType
    value: Decimal

    def calculate_amount(self, subtotal: Decimal) -> Decimal:
        """Calculate the discount amount for the given subtotal."""
        if self.discount_type is DiscountType.PERCENTAGE:
            return subtotal * (self.value / Decimal("100"))

        return min(self.value, subtotal)


class ShoppingCart:
    """A shopping cart that manages items, discounts, and total calculations."""

    def __init__(self) -> None:
        self._items: dict[str, CartItem] = {}
        self._discount: Discount | None = None

    def add_item(self, product_name: str, unit_price: Decimal, quantity: int = 1) -> None:
        """Add an item to the cart, increasing quantity if it already exists."""
        normalized_name = self._validate_product_name(product_name)
        validated_price = self._validate_unit_price(unit_price)
        validated_quantity = self._validate_quantity(quantity)

        existing_item = self._items.get(normalized_name)

        if existing_item is not None:
            if existing_item.unit_price != validated_price:
                raise DuplicateItemPriceMismatchError(
                    f"Product '{normalized_name}' already exists with unit price "
                    f"{existing_item.unit_price}, not {validated_price}."
                )

            self._items[normalized_name] = replace(
                existing_item,
                quantity=existing_item.quantity + validated_quantity,
            )
            return

        self._items[normalized_name] = CartItem(
            product_name=normalized_name,
            unit_price=validated_price,
            quantity=validated_quantity,
        )

    def remove_item(self, product_name: str) -> None:
        """Remove an item from the cart by product name."""
        normalized_name = self._validate_product_name(product_name)
        self._get_existing_item(normalized_name)
        del self._items[normalized_name]

    def update_quantity(self, product_name: str, quantity: int) -> None:
        """Update the quantity of an existing cart item."""
        normalized_name = self._validate_product_name(product_name)
        validated_quantity = self._validate_quantity(quantity)
        existing_item = self._get_existing_item(normalized_name)

        self._items[normalized_name] = replace(existing_item, quantity=validated_quantity)

    def calculate_subtotal(self) -> Decimal:
        """Calculate the subtotal before discounts."""
        return sum(
            (item.line_total for item in self._items.values()),
            Decimal("0"),
        )

    def apply_percentage_discount(self, percentage: Decimal) -> None:
        """Apply a percentage discount to the cart."""
        validated_percentage = self._validate_percentage_discount(percentage)
        self._discount = Discount(
            discount_type=DiscountType.PERCENTAGE,
            value=validated_percentage,
        )

    def apply_flat_discount(self, amount: Decimal) -> None:
        """Apply a flat discount amount to the cart."""
        validated_amount = self._validate_flat_discount(amount)
        self._discount = Discount(
            discount_type=DiscountType.FLAT,
            value=validated_amount,
        )

    def clear_discount(self) -> None:
        """Remove any active discount from the cart."""
        self._discount = None

    def calculate_total(self) -> Decimal:
        """Calculate the final total after discounts."""
        subtotal = self.calculate_subtotal()

        if self._discount is None:
            return subtotal

        return subtotal - self._discount.calculate_amount(subtotal)

    def list_items(self) -> tuple[CartItem, ...]:
        """Return all cart items."""
        return tuple(self._items.values())

    def clear(self) -> None:
        """Remove all items and discounts from the cart."""
        self._items.clear()
        self._discount = None

    def _get_existing_item(self, product_name: str) -> CartItem:
        if product_name not in self._items:
            raise ItemNotFoundError(f"Product '{product_name}' does not exist in the cart.")

        return self._items[product_name]

    @staticmethod
    def _validate_product_name(product_name: str) -> str:
        normalized_name = product_name.strip()

        if not normalized_name:
            raise InvalidProductNameError("Product name must not be empty.")

        return normalized_name

    @staticmethod
    def _validate_unit_price(unit_price: Decimal) -> Decimal:
        if unit_price < Decimal("0"):
            raise InvalidUnitPriceError("Unit price must not be negative.")

        return unit_price

    @staticmethod
    def _validate_quantity(quantity: int) -> int:
        if quantity < 1:
            raise InvalidQuantityError("Quantity must be at least 1.")

        return quantity

    @staticmethod
    def _validate_percentage_discount(percentage: Decimal) -> Decimal:
        if percentage < Decimal("0") or percentage > Decimal("100"):
            raise InvalidDiscountError("Percentage discount must be between 0 and 100.")

        return percentage

    @staticmethod
    def _validate_flat_discount(amount: Decimal) -> Decimal:
        if amount < Decimal("0"):
            raise InvalidDiscountError("Flat discount must not be negative.")

        return amount
